/**
 * Frontier — Encounter Template Data
 *
 * Static encounter templates organized by EncounterType.
 * Used by systems/encounters.ts to generate Encounter instances.
 * Each template produces 2-4 choices with requirements and effects.
 *
 * Per GDD §6: Encounters are generated by Game Logic, not the Narrator.
 */

import { EncounterType } from '@/types/encounters';
import type { EncounterTrigger, EncounterChoice, EncounterOutcome } from '@/types/encounters';
import { Biome, Act } from '@/types/game-state';

// ============================================================
// TEMPLATE INTERFACE
// ============================================================

export interface EncounterTemplate {
  id: string;
  type: EncounterType;
  name: string;
  description: string;
  trigger: EncounterTrigger;
  /** Restrict to these biomes (empty = any) */
  biomes: Biome[];
  /** Restrict to these acts (empty = any) */
  acts: Act[];
  /** Earliest day this can appear */
  minDay: number;
  /** Max times per playthrough (0 = unlimited) */
  maxOccurrences: number;
  /** Base probability before modifiers (0–1) */
  baseProbability: number;
  /** Choice templates — available is always true here, evaluated at runtime */
  choices: EncounterChoice[];
}

